// // This module implements a 5-bit register with enable. The register loads the input data into the register on the negative edge of the clock signal clk when the enable signal en is low. When the reset signal rst is deasserted, the register value is set to 0 on the next negative edge of clk.
module register_with_enable(
    input clk,
    input rst,
    input en,
    input [4:0] data,

    output reg [4:0] q
);
    always @(posedge clk) begin
        if (rst) begin
            q <= 5'b00000;
        end else if (en) begin
            q <= data;
        end
    end
endmodule
